import{_ as e,a,b as o,c as n}from"./chunks/查询额度成功的卡牌.2KCF7h3O.js";import{_ as d,o as l,c as s,a2 as i}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Přidání kanálu S3","description":"","frontmatter":{},"headers":[],"relativePath":"cs-CZ/upload/s3.md","filePath":"cs-CZ/upload/s3.md","lastUpdated":1781962217000}'),p={name:"cs-CZ/upload/s3.md"};function r(c,t,u,h,k,v){return l(),s("div",null,[...t[0]||(t[0]=[i(`<h1 id="pridani-kanalu-s3" tabindex="-1">Přidání kanálu S3 <a class="header-anchor" href="#pridani-kanalu-s3" aria-label="Permalink to &quot;Přidání kanálu S3&quot;">​</a></h1><h2 id="kdy-se-hodi" tabindex="-1">Kdy se hodí <a class="header-anchor" href="#kdy-se-hodi" aria-label="Permalink to &quot;Kdy se hodí&quot;">​</a></h2><p>Kanál S3 použijte, když:</p><ul><li>chcete připojit libovolné S3 kompatibilní objektové úložiště, například Cloudflare R2, Backblaze B2, MinIO, AWS S3 nebo jiného kompatibilního poskytovatele.</li><li>preferujete standardní model konfigurace S3: <code>Endpoint</code>, Access Key a Secret Key.</li><li>nechcete použít nativní kanál Cloudflare R2 přes binding nebo váš poskytovatel není Cloudflare R2.</li></ul><h2 id="co-potrebujete-pred-zacatkem" tabindex="-1">Co potřebujete před začátkem <a class="header-anchor" href="#co-potrebujete-pred-zacatkem" aria-label="Permalink to &quot;Co potřebujete před začátkem&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Požadavek</th><th>Účel</th></tr></thead><tbody><tr><td>S3 Endpoint</td><td>S3 API endpoint služby objektového úložiště.</td></tr><tr><td>Název bucketu</td><td>Bucket, do kterého se budou ukládat soubory.</td></tr><tr><td>Region</td><td>Region úložiště. U Cloudflare R2 obvykle <code>auto</code>.</td></tr><tr><td>Access Key ID</td><td>ID přístupového klíče S3.</td></tr><tr><td>Secret Access Key</td><td>Tajný přístupový klíč S3.</td></tr><tr><td>CDN doména</td><td>Volitelná vlastní doména pro přístup k souborům.</td></tr></tbody></table><p>Příklad pro Cloudflare R2 přes S3 API:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Endpoint: https://your-account-id.r2.cloudflarestorage.com</span></span>
<span class="line"><span>Bucket: your-r2-bucket-name</span></span>
<span class="line"><span>Region: auto</span></span>
<span class="line"><span>Access Key ID: zkopírováno z tokenu Cloudflare R2 API</span></span>
<span class="line"><span>Secret Access Key: zkopírováno z tokenu Cloudflare R2 API</span></span></code></pre></div><h2 id="kde-ho-pridat" tabindex="-1">Kde ho přidat <a class="header-anchor" href="#kde-ho-pridat" aria-label="Permalink to &quot;Kde ho přidat&quot;">​</a></h2><ol><li>Otevřete Nastavení systému.</li><li>Přejděte do Nastavení nahrávání.</li><li>Klikněte vpravo nahoře na Přidat kanál.</li><li>Vyberte <code>S3</code>.</li></ol><h2 id="prehled-poli" tabindex="-1">Přehled polí <a class="header-anchor" href="#prehled-poli" aria-label="Permalink to &quot;Přehled polí&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pole</th><th>Co dělá</th><th>Povinné</th></tr></thead><tbody><tr><td>Název kanálu</td><td>Srozumitelný název, například <code>s3test</code> nebo <code>R2-S3</code>.</td><td>Ano</td></tr><tr><td>Povolit kanál</td><td>Určuje, zda se kanál účastní výběru při nahrávání.</td><td>Doporučeno</td></tr><tr><td>Endpoint</td><td>Úplný endpoint služby S3 včetně <code>https://</code>.</td><td>Ano</td></tr><tr><td>Vlastní CDN doména</td><td>Volitelné. Pokud je nastavena, generované odkazy budou preferovat tuto doménu.</td><td>Ne</td></tr><tr><td>Název bucketu</td><td>Název bucketu, například <code>s3test</code> nebo <code>img-r2</code>.</td><td>Ano</td></tr><tr><td>Region bucketu</td><td>Region. U Cloudflare R2 obvykle <code>auto</code>.</td><td>Ano</td></tr><tr><td>Access Key ID</td><td>ID přístupového klíče S3.</td><td>Ano</td></tr><tr><td>Secret Access Key</td><td>Tajný přístupový klíč S3.</td><td>Ano</td></tr><tr><td>Path-style access</td><td>Přepínač kompatibility. Výchozí je vypnuto. Některé služby MinIO, OpenList nebo self-hosted S3 ho mohou vyžadovat.</td><td>Ne</td></tr><tr><td>Limit kapacity</td><td>Určuje, zda se kanál vybírá podle kapacity.</td><td>Ne</td></tr><tr><td>Kapacitní limit</td><td>Povinný po zapnutí limitu, například <code>10 GB</code>.</td><td>Povinné při limitu</td></tr><tr><td>Prahová hodnota</td><td>Zastaví zápis po dosažení tohoto procenta, například <code>90%</code>.</td><td>Povinné při limitu</td></tr><tr><td>Poznámka</td><td>Poznámky pro vlastní údržbu.</td><td>Ne</td></tr></tbody></table><h2 id="vytvoreni-s3-api-klicu-pro-cloudflare-r2" tabindex="-1">Vytvoření S3 API klíčů pro Cloudflare R2 <a class="header-anchor" href="#vytvoreni-s3-api-klicu-pro-cloudflare-r2" aria-label="Permalink to &quot;Vytvoření S3 API klíčů pro Cloudflare R2&quot;">​</a></h2><ol><li>Otevřete Cloudflare Dashboard.</li><li>Přejděte do <code>R2 Object Storage</code>.</li><li>Najděte <code>Manage R2 API Tokens</code> nebo vstup pro správu API tokenů.</li></ol><p>![Vstup k R2 API tokenům](../../image/upload/s3/r2 api token入口.png)</p><ol start="4"><li>Vytvořte R2 API token s přístupem k cílovému bucketu.</li></ol><p><img src="`+e+'" alt="Vytvoření API tokenu účtu" loading="lazy"></p><ol start="5"><li>Zkopírujte vygenerované <code>Access Key ID</code> a <code>Secret Access Key</code>.</li></ol><p><img src="'+a+'" alt="Kopírování hodnot tokenu" loading="lazy"></p><ol start="6"><li>Vraťte se na stránku R2 bucketu a potvrďte název bucketu.</li><li>Poznamenejte si S3 API endpoint účtu. Obvykle vypadá takto:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-account-id.r2.cloudflarestorage.com</span></span></code></pre></div><h2 id="postup-nastaveni" tabindex="-1">Postup nastavení <a class="header-anchor" href="#postup-nastaveni" aria-label="Permalink to &quot;Postup nastavení&quot;">​</a></h2><ol><li>Otevřete Nastavení nahrávání.</li><li>Klikněte na Přidat kanál.</li><li>Vyberte <code>S3</code>.</li><li>Zadejte srozumitelný název kanálu, například <code>s3test</code>.</li><li>Do <code>Endpoint</code> zadejte S3 API endpoint.</li><li>Pokud používáte vlastní CDN, zadejte ji do <code>Custom CDN domain</code>; jinak nechte pole prázdné.</li><li>Zadejte název bucketu.</li><li>Zadejte region. Pro příklad Cloudflare R2 použijte <code>auto</code>.</li><li>Zadejte Access Key ID a Secret Access Key.</li><li>Path-style access nechte vypnutý, pokud ho poskytovatel výslovně nevyžaduje.</li><li>Pokud chcete řídit kapacitu, zapněte limit a zadejte kapacitní limit i prahovou hodnotu.</li><li>Klikněte na Uložit.</li></ol><p><img src="'+o+'" alt="Přidání konfigurace S3" loading="lazy"></p><h2 id="overeni" tabindex="-1">Ověření <a class="header-anchor" href="#overeni" aria-label="Permalink to &quot;Ověření&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Kontrola</th><th>Jak ověřit</th></tr></thead><tbody><tr><td>Karta kanálu se zobrazuje</td><td>Po uložení by se v Nastavení nahrávání měla zobrazit karta S3.</td></tr><tr><td>Kanál je zapnutý</td><td>Přepínač v pravém horním rohu karty zůstává zapnutý.</td></tr><tr><td>Důležitá pole jsou uložena</td><td>Detail zobrazuje Endpoint, Bucket, Region, Path-style access a související pole.</td></tr><tr><td>Upload funguje</td><td>Nahrajte testovací obrázek a ověřte, že se objekt objevil v cílovém bucketu.</td></tr><tr><td>Odkaz se otevře</td><td>Odkaz na obrázek vrácený po uploadu se normálně otevře.</td></tr><tr><td>Zobrazení kapacity funguje</td><td>Pokud je limit zapnutý, karta ukazuje využitou kapacitu a nastavený limit.</td></tr></tbody></table><p>Statistiky kapacity S3 se počítají z lokálních záznamů souborů v ImgBed, ne z realtime dotazu na bucket poskytovatele. Po uložení konfigurace S3 systém přepočítá evidenci kvót z aktuálních záznamů D1.</p><p><img src="'+n+`" alt="Dotaz na kvótu byl úspěšný" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="mam-zapnout-path-style-access" tabindex="-1">Mám zapnout Path-style access? <a class="header-anchor" href="#mam-zapnout-path-style-access" aria-label="Permalink to &quot;Mám zapnout Path-style access?&quot;">​</a></h3><p>Většinou ne.</p><p>Zapněte ho jen tehdy, když váš S3 kompatibilní poskytovatel nepodporuje virtual-hosted-style URL nebo když to dokumentace poskytovatele výslovně vyžaduje. Některé endpointy MinIO, self-hosted S3 a OpenList ho mohou potřebovat.</p><h3 id="k-cemu-je-cdn-domena" tabindex="-1">K čemu je CDN doména? <a class="header-anchor" href="#k-cemu-je-cdn-domena" aria-label="Permalink to &quot;K čemu je CDN doména?&quot;">​</a></h3><p>Pokud před bucket dáváte CDN nebo vlastní přístupovou doménu, zadejte ji sem.</p><p>Po nastavení budou generované odkazy preferovat tuto doménu. Pokud CDN nepoužíváte, nechte pole prázdné.</p><h3 id="proc-upload-selhava" tabindex="-1">Proč upload selhává? <a class="header-anchor" href="#proc-upload-selhava" aria-label="Permalink to &quot;Proč upload selhává?&quot;">​</a></h3><p>Nejdřív zkontrolujte:</p><ol><li>Endpoint obsahuje úplný URL s <code>https://</code>.</li><li>Název bucketu je správný.</li><li>Region odpovídá požadavkům poskytovatele.</li><li>Access Key ID a Secret Access Key byly zkopírovány celé.</li><li>Klíč má právo zapisovat do cílového bucketu.</li><li>Poskytovatel nevyžaduje Path-style access, nebo je tato volba zapnutá, pokud je potřeba.</li></ol><h2 id="rychly-checklist" tabindex="-1">Rychlý checklist <a class="header-anchor" href="#rychly-checklist" aria-label="Permalink to &quot;Rychlý checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Připravte S3 Endpoint, Bucket, Region, Access Key a Secret Key</span></span>
<span class="line"><span>-&gt; Otevřete Nastavení nahrávání</span></span>
<span class="line"><span>-&gt; Přidat kanál</span></span>
<span class="line"><span>-&gt; Vyberte S3</span></span>
<span class="line"><span>-&gt; Zadejte Endpoint / Bucket / Region / Access Key / Secret Key</span></span>
<span class="line"><span>-&gt; Případně zadejte CDN doménu</span></span>
<span class="line"><span>-&gt; Path-style access nechte ve výchozím stavu vypnutý</span></span>
<span class="line"><span>-&gt; Pokud je potřeba, zapněte limit kapacity</span></span>
<span class="line"><span>-&gt; Uložte</span></span>
<span class="line"><span>-&gt; Nahrajte testovací obrázek a zkontrolujte výsledek</span></span></code></pre></div>`,40)])])}const P=d(p,[["render",r]]);export{m as __pageData,P as default};
